import test from 'node:test';
import assert from 'node:assert/strict';

import { OffsetTracker } from '../src/offset-tracker.mjs';
import { processBatch } from '../src/batch-consumer.mjs';

test('finishing later work first keeps the restart position recoverable', () => {
  const tracker = new OffsetTracker({ 'orders:1': 20 });

  assert.equal(tracker.complete('orders', 1, 22), 20);
  assert.equal(tracker.committed('orders', 1), 20);
  assert.equal(tracker.complete('orders', 1, 21), 22);
  assert.equal(tracker.committed('orders', 1), 22);
});

test('completed work is attributed to its source shard', async () => {
  const calls = [];
  const tracker = {
    complete(...args) {
      calls.push(args);
      return args[2];
    }
  };

  await processBatch(
    [{ topic: 'payments', partition: 4, offset: 31, value: 'captured' }],
    async (record) => record.value,
    tracker
  );

  assert.deepEqual(calls, [['payments', 4, 31]]);
});
